mapper.select:
SELECT
o.platform_type,

COUNT(*) AS total_order_count,

COUNT(
CASE
WHEN o.order_status = 'COMPLETED'
THEN 1
END
) AS completed_order_count,

COUNT(
CASE
WHEN o.order_status = 'CANCELED'
THEN 1
END
) AS canceled_order_count,

COALESCE(
SUM(
CASE
WHEN o.order_status = 'COMPLETED'
THEN COALESCE(o.total_amount, 0)
ELSE 0
END
),
0
) AS total_sales,

COALESCE(
SUM(
CASE
WHEN o.order_status = 'COMPLETED'
THEN COALESCE(o.net_profit, 0)
ELSE 0
END
),
0
) AS total_net_profit

FROM orders o

LEFT JOIN order_requests order_request
ON order_request.order_id = o.id

LEFT JOIN order_cancellations order_cancellation
ON order_cancellation.order_id = o.id

WHERE o.store_id = #{storeId}
AND o.deleted_at IS NULL


    AND (
    (
    o.ordered_at >= #{search.businessStartAt}
    AND o.ordered_at < #{search.businessEndAt}
    )
    OR (
    o.order_status = 'COMPLETED'
    AND o.completed_at IS NOT NULL
    AND o.completed_at >= #{search.businessStartAt}
    AND o.completed_at < #{search.businessEndAt}
    )
    OR (
    o.order_status = 'CANCELED'
    AND o.canceled_at IS NOT NULL
    AND o.canceled_at >= #{search.businessStartAt}
    AND o.canceled_at < #{search.businessEndAt}
    )
    OR (
    o.order_status = 'REFUNDED'
    AND o.refunded_at IS NOT NULL
    AND o.refunded_at >= #{search.businessStartAt}
    AND o.refunded_at < #{search.businessEndAt}
    )
    )



    AND o.platform_type = #{search.platformType}



    AND o.order_status = #{search.orderStatus}



    AND order_request.risk_type = #{search.riskType}



    AND(
    o.order_no LIKE CONCAT('%', #{search.keyword}, '%')
    OR o.platform_order_number LIKE CONCAT('%', #{search.keyword}, '%')
    OR o.delivery_address LIKE CONCAT('%', #{search.keyword}, '%')
    OR order_request.request_text LIKE CONCAT('%', #{search.keyword}, '%')
    OR order_cancellation.cancel_reason LIKE CONCAT('%', #{search.keyword}, '%')
    )


GROUP BY o.platform_type

ORDER BY total_sales DESC,
total_order_count DESC

SELECT order_cancellation.cancel_type AS cancel_type, COUNT(*) AS cancel_count
FROM orders o
INNER JOIN order_cancellations order_cancellation ON order_cancellation.order_id = o.id
LEFT JOIN order_requests order_request ON order_request.order_id = o.id
WHERE o.store_id = #{storeId} AND o.deleted_at IS NULL AND o.order_status = 'CANCELED'
AND o.canceled_at >= #{search.businessStartAt}
AND o.canceled_at < #{search.businessEndAt}
AND o.platform_type = #{search.platformType}
AND order_request.risk_type = #{search.riskType}
AND( o.order_no LIKE CONCAT('%', #{search.keyword}, '%') OR o.platform_order_number LIKE CONCAT('%', #{search.keyword}, '%') OR order_request.request_text LIKE CONCAT('%', #{search.keyword}, '%') OR order_cancellation.cancel_type LIKE CONCAT('%', #{search.keyword}, '%') OR order_cancellation.cancel_reason LIKE CONCAT('%', #{search.keyword}, '%') )
GROUP BY order_cancellation.cancel_type
ORDER BY cancel_count DESC, order_cancellation.cancel_type ASC
